const Summary = ({ M, T, totalInterest }) => {
    
    return(
       <div className='card-header border-top container d-flex justify-content-between p-1 my-2'>
           <div className='d-flex'>Monthly Payment: {M.toFixed(2)}</div>
           <div className='d-flex'>Term: {`${(T/12.0).toFixed(2)} Years`}</div>
           <div className='d-flex'>Total Interest: ${totalInterest}</div>
        </div>
     )
   }
   
   export default Summary;