const Table = ({ data }) => {
    
    return(
        <table className="table table-striped table-sm">
            <thead>
                <tr>
                    <th style={{ width: "15%" }} >Visability</th>
                    <th>Date</th>
                    <th>Balance</th>
                    <th>Principle</th>
                    <th>Interest</th>
                </tr>
            </thead>
            <tbody>
            {data.map((data, i)=>{
                return (
                    <tr key={i}>
                    <td>Enabled</td>
                    <td>{data.name}</td>
                    <td>{data.balance}</td>
                    <td>{data.principle}</td>
                    <td>{data.interest}</td>
                </tr>
                )
            })}
                 

            </tbody>
        </table>
     )
   }
   
   export default Table;