const Header = ({date, setDate}) => {
    
 return(
    <div className='card-header border-top container d-flex justify-content-between p-1'>
        <div className='d-flex'>
          <strong>Scenario </strong>
          <input 
            type="text" 
            name="scenario" 
            id="scenario" 
            value="Base Scenario" 
            className="form-control ml-2 heighttext"
            style={{ width:"150px" }} 
            onChange={e=>console.log(e.target.value)} 
          />
        </div>
        <div className='d-flex'>
          <strong>Start Date</strong>
          <input 
            type="date" 
            name="date" 
            id="date" 
            value={date?date:''} 
            className="form-control ml-2 heighttext" 
            style={{ width:"170px" }}
            onChange={e=>setDate(e.target.value)} 
          />
          </div>
        <div className='d-flex'>
          <strong>Year</strong>
          <input 
            type="text" 
            name="year" 
            id="year" 
            value="2021" 
            className="form-control ml-2 heighttext"
            style={{ width:"80px" }} 
            onChange={e=>console.log(e.target.value)} 
          />
          </div>
      </div>
  )
}

export default Header;